class Interpolation:
    def __init__(self):
        pass

    @staticmethod
    def interpolate_1d(x, y, x_interp):
        from bisect import bisect_right
        y_interp = []
        n = len(x)
        for xi in x_interp:
            if xi < x[0] or xi > x[-1]:
                continue
            i = bisect_right(x, xi) - 1
            if i < 0:
                i = 0
            if i >= n - 1:
                i = n - 2
            dx = x[i+1] - x[i]
            if dx == 0:
                yi = y[i]
            else:
                yi = y[i] + (y[i+1] - y[i]) * (xi - x[i]) / dx
            y_interp.append(yi)
        return y_interp

    @staticmethod
    def interpolate_2d(x, y, z, x_interp, y_interp):
        from bisect import bisect_right
        z_interp = []
        nx = len(x)
        ny = len(y)
        for xi, yi in zip(x_interp, y_interp):
            if xi < x[0] or xi > x[-1] or yi < y[0] or yi > y[-1]:
                continue
            i = bisect_right(x, xi) - 1
            j = bisect_right(y, yi) - 1
            if i < 0:
                i = 0
            if j < 0:
                j = 0
            if i >= nx - 1:
                i = nx - 2
            if j >= ny - 1:
                j = ny - 2
            x0, x1 = x[i], x[i+1]
            y0, y1 = y[j], y[j+1]
            z00 = z[i][j]
            z10 = z[i+1][j]
            z01 = z[i][j+1]
            z11 = z[i+1][j+1]
            dx = x1 - x0
            dy = y1 - y0
            if dx == 0 and dy == 0:
                zi = z00
            elif dx == 0:
                t = (yi - y0) / dy if dy != 0 else 0.0
                zi = z00 + (z01 - z00) * t
            elif dy == 0:
                s = (xi - x0) / dx if dx != 0 else 0.0
                zi = z00 + (z10 - z00) * s
            else:
                s = (xi - x0) / dx
                t = (yi - y0) / dy
                zi = (z00 * (1 - s) * (1 - t) +
                      z10 * s * (1 - t) +
                      z01 * (1 - s) * t +
                      z11 * s * t)
            z_interp.append(zi)
        return z_interp

