class Interpolation:
    def __init__(self):
        pass

    @staticmethod
    def _find_interval(arr, v):
        n = len(arr)
        if v < arr[0] or v > arr[-1]:
            return None
        for k in range(n - 1):
            if arr[k] <= v <= arr[k+1]:
                return k
        return None

    @staticmethod
    def interpolate_1d(x, y, x_interp):
        y_interp = []
        for xv in x_interp:
            idx = Interpolation._find_interval(x, xv)
            if idx is None:
                continue
            x0, x1 = x[idx], x[idx+1]
            y0, y1 = y[idx], y[idx+1]
            if x1 == x0:
                y_interp.append(y0)
            else:
                t = (xv - x0) / (x1 - x0)
                y_interp.append(y0 + t * (y1 - y0))
        return y_interp

    @staticmethod
    def interpolate_2d(x, y, z, x_interp, y_interp):
        z_interp = []
        for xv, yv in zip(x_interp, y_interp):
            ix = Interpolation._find_interval(x, xv)
            iy = Interpolation._find_interval(y, yv)
            if ix is None or iy is None:
                continue
            x0, x1 = x[ix], x[ix+1]
            y0, y1 = y[iy], y[iy+1]
            z00 = z[ix][iy]
            z10 = z[ix+1][iy]
            z01 = z[ix][iy+1]
            z11 = z[ix+1][iy+1]
            dx = x1 - x0
            dy = y1 - y0
            if dx == 0 and dy == 0:
                z_interp.append(z00)
                continue
            if dx == 0:
                ty = (yv - y0) / dy if dy != 0 else 0.0
                z_interp.append(z00 + ty * (z01 - z00))
                continue
            if dy == 0:
                tx = (xv - x0) / dx if dx != 0 else 0.0
                z_interp.append(z00 + tx * (z10 - z00))
                continue
            tx = (xv - x0) / dx
            ty = (yv - y0) / dy
            zi = (z00 * (1 - tx) * (1 - ty) +
                  z10 * tx * (1 - ty) +
                  z01 * (1 - tx) * ty +
                  z11 * tx * ty)
            z_interp.append(zi)
        return z_interp

