class Interpolation:
    def __init__(self):
        pass

    @staticmethod
    def interpolate_1d(x, y, x_interp):
        # build segments
        segments = []
        for i in range(len(x) - 1):
            x0, x1 = x[i], x[i+1]
            y0, y1 = y[i], y[i+1]
            dx = x1 - x0
            if dx == 0:
                m = 0.0
            else:
                m = (y1 - y0) / dx
            segments.append((x0, x1, y0, m))
        out = []
        for xv in x_interp:
            for x0, x1, y0, m in segments:
                if x0 <= xv <= x1:
                    out.append(y0 + m * (xv - x0))
                    break
        return out

    @staticmethod
    def interpolate_2d(x, y, z, x_interp, y_interp):
        # for each query, perform bilinear via two linear interpolations in x then y
        out = []
        for xv, yv in zip(x_interp, y_interp):
            # find i
            i = None
            for ii in range(len(x) - 1):
                if x[ii] <= xv <= x[ii+1]:
                    i = ii
                    break
            j = None
            for jj in range(len(y) - 1):
                if y[jj] <= yv <= y[jj+1]:
                    j = jj
                    break
            if i is None or j is None:
                continue
            x0, x1 = x[i], x[i+1]
            y0, y1 = y[j], y[j+1]
            z00 = z[i][j]
            z10 = z[i+1][j]
            z01 = z[i][j+1]
            z11 = z[i+1][j+1]
            dx = x1 - x0
            dy = y1 - y0
            if dx == 0:
                zx0 = z00
                zx1 = z01
            else:
                t = (xv - x0) / dx
                zx0 = z00 + t * (z10 - z00)
                zx1 = z01 + t * (z11 - z01)
            if dy == 0:
                out.append(zx0)
            else:
                s = (yv - y0) / dy
                out.append(zx0 + s * (zx1 - zx0))
        return out

