class IPAddress:
    def __init__(self, ip_address):
        self.ip_address = ip_address

    def is_valid(self):
        parts = self.ip_address.split('.')
        if len(parts) != 4:
            return False
        for p in parts:
            if p == '':
                return False
            try:
                n = int(p)
            except ValueError:
                return False
            if n < 0 or n > 255:
                return False
        return True

    def get_octets(self):
        return self.ip_address.split('.') if self.is_valid() else []

    def get_binary(self):
        if not self.is_valid():
            return ''
        return '.'.join(format(int(o), '08b') for o in self.get_octets())

