import re

class IPAddress:
    _pattern = re.compile(r'^(?:25[0-5]|2[0-4]\d|1?\d{1,2})(?:\.(?:25[0-5]|2[0-4]\d|1?\d{1,2})){3}$')

    def __init__(self, ip_address):
        self.ip_address = ip_address

    def is_valid(self):
        return bool(self._pattern.fullmatch(self.ip_address))

    def get_octets(self):
        return self.ip_address.split('.') if self.is_valid() else []

    def get_binary(self):
        if not self.is_valid():
            return ''
        return '.'.join(f"{int(o):08b}" for o in self.get_octets())

