import ipaddress

class IPAddress:
    def __init__(self, ip_address):
        self.ip_address = ip_address

    def is_valid(self):
        try:
            addr = ipaddress.ip_address(self.ip_address)
        except ValueError:
            return False
        return addr.version == 4

    def get_octets(self):
        if not self.is_valid():
            return []
        return self.ip_address.split('.')

    def get_binary(self):
        if not self.is_valid():
            return ''
        return '.'.join(bin(int(o))[2:].zfill(8) for o in self.get_octets())

