from dataclasses import dataclass

@dataclass
class IPAddress:
    ip_address: str

    def is_valid(self) -> bool:
        octets = self.ip_address.split('.')
        if len(octets) != 4:
            return False
        return all(o.isdigit() and 0 <= int(o) <= 255 for o in octets)

    def get_octets(self):
        return self.ip_address.split('.') if self.is_valid() else []

    def get_binary(self):
        if not self.is_valid():
            return ''
        octs = self.get_octets()
        return '.'.join(format(int(o), '08b') for o in octs)

