class IPAddress:
    def __init__(self, ip_address):
        self.ip_address = ip_address

    def is_valid(self):
        parts = list(map(str.strip, self.ip_address.split('.')))
        if len(parts) != 4:
            return False
        try:
            nums = list(map(int, parts))
        except ValueError:
            return False
        return all(0 <= n <= 255 for n in nums)

    def get_octets(self):
        return self.ip_address.split('.') if self.is_valid() else []

    def get_binary(self):
        if not self.is_valid():
            return ''
        return '.'.join(bin(int(x))[2:].rjust(8, '0') for x in self.get_octets())

