import socket

class IpUtil:

    @staticmethod
    def is_valid_ipv4(ip_address):
        if not isinstance(ip_address, str):
            return False
        parts = ip_address.split('.')
        if len(parts) != 4:
            return False
        try:
            socket.inet_aton(ip_address)
        except (socket.error, OSError):
            return False
        for p in parts:
            if not p.isdigit() or not 0 <= int(p) <= 255:
                return False
        return True

    @staticmethod
    def is_valid_ipv6(ip_address):
        if not isinstance(ip_address, str):
            return False
        try:
