import socket
import ipaddress
from typing import Optional

class IpUtil:

    @staticmethod
    def is_valid_ipv4(ip_address) -> bool:
        try:
            a = ipaddress.ip_address(ip_address)
            return a.version == 4
        except (ValueError, TypeError):
            return False

    @staticmethod
    def is_valid_ipv6(ip_address) -> bool:
        try:
            a = ipaddress.ip_address(ip_address)
            return a.version == 6
        except (ValueError, TypeError):
            return False

    @staticmethod
    def get_hostname(ip_address) -> Optional[str]:
        try:
            name = socket.gethostbyaddr(ip_address)[0]
            return name
        except (socket.herror, socket.gaierror):
            try:
                fqdn = socket.getfqdn(ip_address)
                if fqdn and fqdn != ip_address:
                    return fqdn
            except Exception:
                pass
            return None

