from dataclasses import dataclass, field
from typing import List

@dataclass
class Job:
    job_title: str
    company: str
    requirements: List[str] = field(default_factory=list)

@dataclass
class Resume:
    name: str
    skills: List[str] = field(default_factory=list)
    experience: int = 0

class JobMarketplace:
    def __init__(self):
        self.job_listings: List[Job] = []
        self.resumes: List[Resume] = []

    def post_job(self, job_title, company, requirements):
        job = Job(job_title=job_title, company=company, requirements=list(requirements))
        self.job_listings.append(job)
        return job

    def remove_job(self, job):
        self.job_listings.remove(job)

    def submit_resume(self, name, skills, experience):
        resume = Resume(name=name, skills=list(skills), experience=experience)
        self.resumes.append(resume)
        return resume

    def withdraw_resume(self, resume):
        self.resumes.remove(resume)

    def search_jobs(self, criteria):
        crit = criteria.lower()
        matches = []
        for job in self.job_listings:
            if crit in job.job_title.lower() or crit in job.company.lower():
                matches.append(job)
                continue
            for req in job.requirements:
                if crit in req.lower():
                    matches.append(job)
                    break
        return matches

    def get_job_applicants(self, job):
        applicants = []
        for resume in self.resumes:
            if self.matches_requirements(resume, job.requirements):
                applicants.append(resume)
        return applicants

    @staticmethod
    def matches_requirements(resume, requirements):
        req_set = {r.lower() for r in requirements}
        skill_set = {s.lower() for s in resume.skills}
        return req_set.issubset(skill_set)

