            self.resumes.remove(resume)
            return True
        return False

    def search_jobs(self, criteria):
        crit = criteria.lower()
        matches = []
        for job in self.job_listings:
            if crit in job["job_title"].lower() or crit in job["company"].lower():
                matches.append(job)
                continue
            for req in job["requirements"]:
                if crit in req.lower():
                    matches.append(job)
                    break
        return matches

    def get_job_applicants(self, job):
        applicants = [r for r in self.resumes if self.matches_requirements(r, job["requirements"])]
        return applicants

    @staticmethod
    def matches_requirements(resume, requirements):
        reqs = set(req.lower() for req in requirements)
        skills = set(s.lower() for s in resume["skills"])
        return reqs <= skills

