import itertools

class JobMarketplace:
    def __init__(self):
        self._job_counter = itertools.count(1)
        self._resume_counter = itertools.count(1)
        self.job_listings = {}
        self.resumes = {}

    def post_job(self, job_title, company, requirements):
        job_id = next(self._job_counter)
        self.job_listings[job_id] = {"id": job_id, "job_title": job_title, "company": company, "requirements": list(requirements)}
        return job_id

    def remove_job(self, job_id):
        if job_id in self.job_listings:
            del self.job_listings[job_id]
            return True
        return False

    def submit_resume(self, name, skills, experience):
        resume_id = next(self._resume_counter)
        self.resumes[resume_id] = {"id": resume_id, "name": name, "skills": list(skills), "experience": experience}
        return resume_id

    def withdraw_resume(self, resume_id):
        if resume_id in self.resumes:
            del self.resumes[resume_id]
            return True
        return False

    def search_jobs(self, criteria):
        crit = criteria.lower()
        results = []
        for job in self.job_listings.values():
            if crit in job["job_title"].lower() or crit in job["company"].lower():
                results.append(job)
                continue
            if any(crit in req.lower() for req in job["requirements"]):
                results.append(job)
        return results

    def get_job_applicants(self, job_id):
        if job_id not in self.job_listings:
            return []
        job = self.job_listings[job_id]
        applicants = []
        for resume in self.resumes.values():
            if self.matches_requirements(resume, job["requirements"]):
                applicants.append(resume)
        return applicants

    @staticmethod
    def matches_requirements(resume, requirements):
        reqs = set(r.lower() for r in requirements)
        skills = set(s.lower() for s in resume["skills"])
        return reqs.issubset(skills)

