    def withdraw_resume(self, resume):
        if resume not in self.resumes:
            raise ValueError("Resume not found")
        self.resumes.remove(resume)

    def search_jobs(self, criteria):
        crit = criteria.lower()
        return [
            job for job in self.job_listings
            if crit in job["job_title"].lower()
            or crit in job["company"].lower()
            or any(crit in req.lower() for req in job["requirements"])
        ]

    def get_job_applicants(self, job):
        return [r for r in self.resumes if self.matches_requirements(r, job["requirements"])]

    @staticmethod
    def matches_requirements(resume, requirements):
        skills = {s.lower() for s in resume["skills"]}
        reqs = {r.lower() for r in requirements}
        return reqs.issubset(skills)

