import re

class JobMarketplace:
    def __init__(self):
        self.job_listings = []
        self.resumes = []

    def post_job(self, job_title, company, requirements):
        job = {"job_title": job_title, "company": company, "requirements": list(requirements)}
        self.job_listings.append(job)
        return job

    def remove_job(self, job):
        try:
            self.job_listings.remove(job)
            return True
        except ValueError:
            return False

    def submit_resume(self, name, skills, experience):
        resume = {"name": name, "skills": list(skills), "experience": experience}
        self.resumes.append(resume)
        return resume

    def withdraw_resume(self, resume):
        try:
            self.resumes.remove(resume)
            return True
        except ValueError:
            return False

    def search_jobs(self, criteria):
        pattern = re.compile(re.escape(criteria), re.IGNORECASE)
        matches = []
        for job in self.job_listings:
            if pattern.search(job["job_title"]) or pattern.search(job["company"]):
                matches.append(job)
                continue
            if any(pattern.search(req) for req in job["requirements"]):
                matches.append(job)
        return matches

    def get_job_applicants(self, job):
        scored = []
        reqs = [r.lower() for r in job["requirements"]]
        for resume in self.resumes:
            match_count = sum(1 for s in resume["skills"] if s.lower() in reqs)
            if match_count > 0:
                r = dict(resume)
                r["match_score"] = match_count
                scored.append(r)
        scored.sort(key=lambda x: x["match_score"], reverse=True)
        return scored

    @staticmethod
    def matches_requirements(resume, requirements):
        reqs = set(r.lower() for r in requirements)
        skills = set(s.lower() for s in resume["skills"])
        return reqs.issubset(skills)

