import json
import os
from pathlib import Path
from json.decoder import JSONDecodeError
import shutil

class JSONProcessor:
    def read_json(self, file_path):
        p = Path(file_path)
        if not p.exists():
            return 0
        try:
            with p.open('r', encoding='utf-8') as f:
                return json.load(f)
        except JSONDecodeError:
            return -1
        except Exception:
            return -1

    def write_json(self, data, file_path):
        p = Path(file_path)
        backup = p.with_suffix(p.suffix + '.bak')
        try:
            if p.exists():
                shutil.copy2(p, backup)
            with p.open('w', encoding='utf-8') as f:
                json.dump(data, f)
            if backup.exists():
                backup.unlink()
            return 1
        except Exception:
            try:
                if backup.exists():
                    shutil.move(str(backup), str(p))
            except Exception:
                pass
            return -1

    def process_json(self, file_path, remove_key):
        data = self.read_json(file_path)
        if data in (0, -1):
            return 0
        if isinstance(data, dict) and remove_key in data:
            data.pop(remove_key, None)
            return 1 if self.write_json(data, file_path) == 1 else 0
        return 0

