import numpy as np

class KappaCalculator:
    @staticmethod
    def kappa(testData, k):
        mat = np.asarray(testData, dtype=float)
        if mat.size == 0:
            return 0.0
        total = mat.sum()
        if total == 0:
            return 0.0
        diag_sum = np.trace(mat)
        observed = diag_sum / total
        row_sums = mat.sum(axis=1).ravel()
        col_sums = mat.sum(axis=0).ravel()
        expected = float(np.dot(row_sums, col_sums)) / (total * total)
        denom = 1.0 - expected
        if denom == 0:
            return 0.0
        return float((observed - expected) / denom)

    @staticmethod
    def fleiss_kappa(testData, N, k, n):
        mat = np.asarray(testData, dtype=float)
        if mat.size == 0 or N == 0 or n <= 1:
            return 0.0
        row_squares = np.sum(mat * mat, axis=1)
        P_i = (row_squares - n) / (n * (n - 1))
        Pbar = P_i.mean()
        p_j = mat.sum(axis=0) / (N * n)
        Pbar_e = float(np.sum(p_j * p_j))
        denom = 1.0 - Pbar_e
        if denom == 0:
            return 0.0
        return float((Pbar - Pbar_e) / denom)

