import numpy as np

class KappaCalculator:
    @staticmethod
    def kappa(testData, k):
        arr = np.array(testData, dtype=np.float64)
        if arr.size == 0:
            return 0.0
        total = arr.sum()
        if total == 0:
            return 0.0
        observed = np.einsum('ii->', arr) / total
        row = arr.sum(axis=1).flatten()
        col = arr.sum(axis=0).flatten()
        expected = np.einsum('i,i->', row, col) / (total * total)
        if 1.0 - expected == 0.0:
