        return float((observed - expected) / (1.0 - expected))

    @staticmethod
    def fleiss_kappa(testData, N, k, n):
        arr = np.array(testData, dtype=np.float64)
        if arr.size == 0 or N == 0 or n <= 1:
            return 0.0
        row_sq = np.einsum('ij,ij->i', arr, arr)
        P_i = (row_sq - n) / (n * (n - 1))
        Pbar = P_i.mean()
        p_j = arr.sum(axis=0) / (N * n)
        Pbar_e = float((p_j * p_j).sum())
        denom = 1.0 - Pbar_e
        if denom == 0.0:
            return 0.0
        return float((Pbar - Pbar_e) / denom)

