class KappaCalculator:
    @staticmethod
    def kappa(testData, k):
        mat = np.asarray(testData, dtype=float)
        if mat.ndim != 2 or mat.shape[0] < k or mat.shape[1] < k:
            mat = mat.reshape((k, k))
        total = mat.sum()
