        sum_sq = np.sum(mat * mat, axis=1)
        P_i = (sum_sq - n) / (n * (n - 1))
        Pbar = P_i.mean()
        p_j = mat.sum(axis=0) / (N * n)
        Pbar_e = float((p_j ** 2).sum())
        if Pbar_e >= 1.0:
            return 0.0
        return float((Pbar - Pbar_e) / (1.0 - Pbar_e))

