import numpy as np

class KappaCalculator:
    @staticmethod
    def kappa(testData, k):
        data = np.array(testData, dtype=float)
        if data.size == 0:
            return 0.0
        total = data.sum()
        if total == 0:
            return 0.0
        diag = sum(data[i, i] for i in range(min(k, data.shape[0], data.shape[1])))
        observed = diag / total
        row = data.sum(axis=1).A1 if hasattr(data.sum(axis=1), 'A1') else data.sum(axis=1).ravel()
        col = data.sum(axis=0).A1 if hasattr(data.sum(axis=0), 'A1') else data.sum(axis=0).ravel()
        expected = float(sum(row[i] * col[i] for i in range(len(row)))) / (total * total)
        if (1 - expected) == 0:
            return 0.0
        return float((observed - expected) / (1 - expected))

    @staticmethod
    def fleiss_kappa(testData, N, k, n):
        data = np.array(testData, dtype=float)
        if data.size == 0 or N == 0 or n <= 1:
            return 0.0
        P_list = []
        for i in range(N):
            s = sum(v * v for v in data[i])
            P_i = (s - n) / (n * (n - 1))
            P_list.append(P_i)
        Pbar = sum(P_list) / N
        p_j = [sum(data[i][j] for i in range(N)) / (N * n) for j in range(k)]
        Pbar_e = sum(x * x for x in p_j)
        if (1 - Pbar_e) == 0:
            return 0.0
        return float((Pbar - Pbar_e) / (1 - Pbar_e))

