import nltk
import re
from nltk.stem import WordNetLemmatizer
from nltk import pos_tag
nltk.download('averaged_perceptron_tagger', quiet=True)
nltk.download('wordnet', quiet=True)

class Lemmatization:
    def __init__(self):
        self.lemmatizer = WordNetLemmatizer()
        self._cache = {}

    def _tokenize(self, sentence):
        return re.findall(r"\b\w+\b", sentence)

    def _map_pos(self, tag):
        if not tag:
            return None
        t = tag[0].upper()
        return {'J': 'a', 'V': 'v', 'N': 'n', 'R': 'r'}.get(t, None)

    def lemmatize_sentence(self, sentence):
        key = ('lemmatize', sentence)
        if key in self._cache:
            return self._cache[key][:]
        words = self._tokenize(self.remove_punctuation(sentence))
        tags = pos_tag(words)
        out = []
        for w, t in tags:
            wn = self._map_pos(t)
            if wn:
                out.append(self.lemmatizer.lemmatize(w, pos=wn))
            else:
                out.append(self.lemmatizer.lemmatize(w))
        self._cache[key] = out[:]
        return out

    def get_pos_tag(self, sentence):
        words = self._tokenize(self.remove_punctuation(sentence))
        return [tag for (_, tag) in pos_tag(words)]

    def remove_punctuation(self, sentence):
        return re.sub(r'[^\w\s]', '', sentence)

