class Lemmatization:
    def __init__(self):
        self.lemmatizer = WordNetLemmatizer()

    def _map_tag(self, tag):
        if not tag:
            return None
        first = tag[0].upper()
        mapping = {'J': 'a', 'V': 'v', 'N': 'n', 'R': 'r'}
        return mapping.get(first, None)

    def lemmatize_sentence(self, sentence):
        cleaned = self.remove_punctuation(sentence)
        tokens = word_tokenize(cleaned)
        tags = pos_tag(tokens)
        lemmas = []
        for tok, tg in tags:
            pos = self._map_tag(tg)
            if pos:
                lemmas.append(self.lemmatizer.lemmatize(tok, pos=pos))
            else:
                if re.fullmatch(r'\d+(\.\d+)?', tok):
                    lemmas.append(tok)
                else:
                    lemmas.append(self.lemmatizer.lemmatize(tok))
        return lemmas

    def get_pos_tag(self, sentence):
        cleaned = self.remove_punctuation(sentence)
        tokens = word_tokenize(cleaned)
        return [t for (_, t) in pos_tag(tokens)]

    def remove_punctuation(self, sentence):
        return re.sub(r'[^\w\s]', '', sentence)

