class LongestWord:
    def __init__(self):
        self._map: Dict[str, str] = {}

    def add_word(self, word):
        key = word.lower()
        if key not in self._map or len(word) > len(self._map[key]):
            self._map[key] = word

    def find_longest_word(self, sentence):
        words = re.findall(r'\b\w+\b', sentence.lower())
        longest_key = ''
        for w in words:
            if w in self._map and len(w) > len(longest_key):
                longest_key = w
        return self._map.get(longest_key, '')

