class ExpandCenter:
    def __init__(self, input_string) -> None:
        self.s = input_string

    def _expand(self, left, right):
        s = self.s
        while left >= 0 and right < len(s) and s[left] == s[right]:
            left -= 1
            right += 1
        return left + 1, right  # start inclusive, end exclusive

    def palindromic_string(self):
        s = self.s
        n = len(s)
        if n == 0:
            return ""
        best_start, best_end = 0, 1
        for i in range(n):
            l1, r1 = self._expand(i, i)
            if r1 - l1 > best_end - best_start:
                best_start, best_end = l1, r1
            l2, r2 = self._expand(i, i + 1)
            if r2 - l2 > best_end - best_start:
                best_start, best_end = l2, r2
        return s[best_start:best_end]

