        if len(data) == 0:
            return 0.0, [0.0]
        if isinstance(data, tuple):
            sub_list, total_num = data
            sub_list = np.asarray(sub_list)
            if total_num == 0:
                return 0.0, [0.0]
            idx = np.where(sub_list > 0)[0]
            if idx.size == 0:
                return 0.0, [0.0]
            rr = 1.0 / (idx[0] + 1)
            return float(rr), [float(rr)]
        results = []
        for sub_list, total_num in data:
            sub_list = np.asarray(sub_list)
            if total_num == 0:
                results.append(0.0)
            else:
                idx = np.where(sub_list > 0)[0]
                if idx.size == 0:
                    results.append(0.0)
                else:
                    results.append(float(1.0 / (idx[0] + 1)))
        return float(np.mean(results)), results

    @staticmethod
    def map(data):
        if not isinstance(data, (list, tuple)):
            raise Exception("the input must be a tuple([0,...,1,...],int) or a iteration of list of tuple")
        if len(data) == 0:
            return 0.0, [0.0]
        if isinstance(data, tuple):
            sub_list, total_num = data
            sub_list = np.asarray(sub_list)
            if total_num == 0:
                return 0.0, [0.0]
            rel = (sub_list > 0).astype(float)
            ranks = np.arange(1, len(sub_list) + 1)
            precisions = np.cumsum(rel) / ranks
            ap = float(np.sum(precisions * rel) / total_num)
            return ap, [ap]
        results = []
        for sub_list, total_num in data:
            sub_list = np.asarray(sub_list)
            if total_num == 0:
                results.append(0.0)
            else:
                rel = (sub_list > 0).astype(float)
                ranks = np.arange(1, len(sub_list) + 1)
                precisions = np.cumsum(rel) / ranks
                ap = float(np.sum(precisions * rel) / total_num)
                results.append(ap)
        return float(np.mean(results)), results

