        self.score = 0

    def _build_map(self):
        coords = list(itertools.product(range(self.n), range(self.n)))
        random.shuffle(coords)
        mines = set(coords[:self.k])
        grid = [[0 for _ in range(self.n)] for _ in range(self.n)]
        for r, c in mines:
            grid[r][c] = 'X'
        for r, c in mines:
            for rr in range(r - 1, r + 2):
                for cc in range(c - 1, c + 2):
