from datetime import datetime

class Movie:
    def __init__(self, name, price, start_time, end_time, n):
        self.name = name
        self.price = price
        self.start_time = datetime.strptime(start_time, '%H:%M')
        self.end_time = datetime.strptime(end_time, '%H:%M')
        self.n = n
        self.seats = [[False]*n for _ in range(n)]

    def book(self, seats):
        for r, c in seats:
            if r < 0 or c < 0 or r >= self.n or c >= self.n:
                return False
            if self.seats[r][c]:
                return False
        for r, c in seats:
            self.seats[r][c] = True
        return True

