from datetime import datetime
from dataclasses import dataclass, field

@dataclass
class Movie:
    name: str
    price: float
    start_time: datetime
    end_time: datetime
    n: int
    booked: set = field(default_factory=set)

    @classmethod
    def create(cls, name, price, start_time, end_time, n):
        st = datetime.strptime(start_time, '%H:%M')
        et = datetime.strptime(end_time, '%H:%M')
        return cls(name, price, st, et, n)

    def can_book(self, seats):
        for r, c in seats:
            if not (0 <= r < self.n and 0 <= c < self.n):
                return False
            if (r, c) in self.booked:
                return False
        return True

    def book(self, seats):
        if not self.can_book(seats):
            return False
        for s in seats:
            self.booked.add(s)
        return True

class MovieBookingSystem:
    def __init__(self):
        self.movies = {}

    def add_movie(self, name, price, start_time, end_time, n):
        self.movies[name] = Movie.create(name, price, start_time, end_time, n)

    def book_ticket(self, name, seats_to_book):
        movie = self.movies.get(name)
        if movie is None:
            return "Movie not found."
        if movie.book(seats_to_book):
            return "Booking success."
        return "Booking failed."

    def available_movies(self, start_time, end_time):
        st = datetime.strptime(start_time, '%H:%M')
        et = datetime.strptime(end_time, '%H:%M')
        return [m.name for m in self.movies.values() if st <= m.start_time and m.end_time <= et]

