from typing import List, Dict


class MovieTicketDB:
    def __init__(self, db_name: str):
        self.conn = sqlite3.connect(db_name)
        self.conn.row_factory = lambda cursor, row: {col[0]: row[idx] for idx, col in enumerate(cursor.description)}
        self._create_table()

    def _create_table(self):
        self.conn.execute('''
            CREATE TABLE IF NOT EXISTS tickets (
                id INTEGER PRIMARY KEY,
                movie_name TEXT,
                theater_name TEXT,
                seat_number TEXT,
                customer_name TEXT
            )
        ''')
        self.conn.commit()

    def insert_ticket(self, movie_name: str, theater_name: str, seat_number: str, customer_name: str) -> int:
        cur = self.conn.execute('''
            INSERT INTO tickets (movie_name, theater_name, seat_number, customer_name)
            VALUES (?, ?, ?, ?)
        ''', (movie_name, theater_name, seat_number, customer_name))
        self.conn.commit()
        return cur.lastrowid

    def search_tickets_by_customer(self, customer_name: str) -> List[Dict]:
        cur = self.conn.execute('SELECT * FROM tickets WHERE customer_name = ?', (customer_name,))
        return cur.fetchall()

    def delete_ticket(self, ticket_id: int) -> bool:
        cur = self.conn.execute('DELETE FROM tickets WHERE id = ?', (ticket_id,))
        self.conn.commit()
        return cur.rowcount > 0

    def list_tickets(self) -> List[Dict]:
        cur = self.conn.execute('SELECT * FROM tickets')
        return cur.fetchall()

    def __del__(self):
        try:
            self.conn.close()
        except Exception:
            pass

