    def _ensure_table(self):
        with self.conn:
            self.conn.execute('''
                CREATE TABLE IF NOT EXISTS tickets (
                    id INTEGER PRIMARY KEY,
                    movie_name TEXT,
                    theater_name TEXT,
                    seat_number TEXT,
                    customer_name TEXT
                )
            ''')

    def insert_ticket(self, movie_name: str, theater_name: str, seat_number: str, customer_name: str) -> int:
        cur = self.conn.execute('''
            INSERT INTO tickets (movie_name, theater_name, seat_number, customer_name)
            VALUES (?, ?, ?, ?)
        ''', (movie_name, theater_name, seat_number, customer_name))
        return cur.lastrowid

    def insert_many(self, tickets: Iterable[Tuple[str, str, str, str]]) -> int:
        cur = self.conn.executemany('''
            INSERT INTO tickets (movie_name, theater_name, seat_number, customer_name)
            VALUES (?, ?, ?, ?)
        ''', tickets)
        return cur.rowcount

    def search_tickets_by_customer(self, customer_name: str):
        cur = self.conn.execute('SELECT id, movie_name, theater_name, seat_number, customer_name FROM tickets WHERE customer_name = ?', (customer_name,))
        return cur.fetchall()

    def delete_ticket(self, ticket_id: int) -> bool:
        cur = self.conn.execute('DELETE FROM tickets WHERE id = ?', (ticket_id,))
        return cur.rowcount > 0

    def get_ticket(self, ticket_id: int):
        cur = self.conn.execute('SELECT id, movie_name, theater_name, seat_number, customer_name FROM tickets WHERE id = ?', (ticket_id,))
        return cur.fetchone()

