import random

class MusicPlayer:
    def __init__(self):
        self.playlist = deque()
        self.volume = 50

    def add_song(self, song):
        self.playlist.append(song)
        return True

    def remove_song(self, song):
        try:
            idx = list(self.playlist).index(song)
        except ValueError:
            return False
        # remove by reconstructing deque without the song
        new_list = []
        removed = False
        for i, s in enumerate(self.playlist):
            if i == idx and not removed and s == song:
                removed = True
                continue
            new_list.append(s)
        self.playlist = deque(new_list)
        return True

    def _current(self):
        return self.playlist[0] if self.playlist else None

    def play(self):
        if not self.playlist:
            return False
        return self._current()

    def stop(self):
        if not self.playlist:
            return False
        # stopping means there is no current song; represent by rotating so that front becomes None conceptually
        # We simulate stop by setting an internal flag: perform by clearing and re-adding? Simpler: keep playlist and track stopped state
        # Implement stopped state as a marker at front
        if getattr(self, "_stopped", False):
            return False
        self._stopped = True
        return True

    def switch_song(self):
        if not self.playlist:
            return False
        if getattr(self, "_stopped", False):
            return False
        if len(self.playlist) == 1:
            return False
        self.playlist.rotate(-1)
        return True

    def previous_song(self):
        if not self.playlist:
            return False
        if getattr(self, "_stopped", False):
            return False
        if len(self.playlist) == 1:
            return False
        self.playlist.rotate(1)
        return True

    def set_volume(self, volume):
        try:
            v = int(volume)
        except (TypeError, ValueError):
            return False
        if 0 <= v <= 100:
            self.volume = v
            return True
        return False

    def shuffle(self):
        if not self.playlist:
            return False
        current = self._current()
        lst = list(self.playlist)
        random.shuffle(lst)
        self.playlist = deque(lst)
        # keep stopped state as-is
        if getattr(self, "_stopped", False):
            return True
        # attempt to restore current song to front if it existed
        if current in self.playlist:
            while self._current() != current:
                self.playlist.rotate(-1)
        return True

