            raise TypeError("decimal_num must be an integer")
        if decimal_num < 0:
            return "-" + format(-decimal_num, "b")
        return format(decimal_num, "b")

    @staticmethod
    def binary_to_decimal(binary_num) -> int:
        if isinstance(binary_num, int):
            binary_num = str(binary_num)
        s = str(binary_num).strip().replace("_", "")
        sign = -1 if s.startswith("-") else 1
        if s.startswith(("+", "-")):
            s = s[1:]
        if s.startswith("0b") or s.startswith("0B"):
            s = s[2:]
        return sign * int(s, 2)

