class ManualNumberConverter:
    DIGITS = "0123456789ABCDEF"

    @staticmethod
    def _to_base(n, base):
        if not isinstance(n, int):
            raise TypeError("n must be int")
        if n == 0:
            return "0"
        sign = "-" if n < 0 else ""
        n = abs(n)
        parts = []
        while n > 0:
            parts.append(ManualNumberConverter.DIGITS[n % base])
            n //= base
        return sign + "".join(reversed(parts))

    @staticmethod
    def _from_base(s, base):
        if isinstance(s, int):
            s = str(s)
        s = s.strip().upper()
        sign = -1 if s.startswith("-") else 1
        if s.startswith(("+", "-")):
            s = s[1:]
        if s.startswith("0X") or s.startswith("0B") or s.startswith("0O"):
            if base == 16 and s.startswith("0X"):
                s = s[2:]
            elif base == 2 and s.startswith("0B"):
                s = s[2:]
            elif base == 8 and s.startswith("0O"):
                s = s[2:]
        value = 0
        for ch in s:
            if ch not in ManualNumberConverter.DIGITS[:base]:
                raise ValueError(f"Invalid digit '{ch}' for base {base}")
            value = value * base + ManualNumberConverter.DIGITS.index(ch)
        return sign * value

    @staticmethod
    def decimal_to_binary(n):
        return ManualNumberConverter._to_base(n, 2)

    @staticmethod
    def binary_to_decimal(s):
        return ManualNumberConverter._from_base(s, 2)

    @staticmethod
    def decimal_to_octal(n):
        return ManualNumberConverter._to_base(n, 8)

    @staticmethod
    def octal_to_decimal(s):
        return ManualNumberConverter._from_base(s, 8)

    @staticmethod
    def decimal_to_hex(n):
        return ManualNumberConverter._to_base(n, 16).lower()

    @staticmethod
    def hex_to_decimal(s):
        return ManualNumberConverter._from_base(s, 16)

