class NumberWordFormatter:
    def __init__(self):
        self.UNITS = ["", "ONE", "TWO", "THREE", "FOUR", "FIVE", "SIX", "SEVEN", "EIGHT", "NINE"]
        self.TEENS = ["TEN", "ELEVEN", "TWELVE", "THIRTEEN", "FOURTEEN", "FIFTEEN", "SIXTEEN", "SEVENTEEN", "EIGHTEEN", "NINETEEN"]
        self.TENS = ["", "TEN", "TWENTY", "THIRTY", "FORTY", "FIFTY", "SIXTY", "SEVENTY", "EIGHTY", "NINETY"]
        self.SCALES = ["", "THOUSAND", "MILLION", "BILLION", "TRILLION"]
    def format(self, x):
        if x is None:
            return ""
        return self.format_string(str(x))
    def format_string(self, x):
        parts = (x.split('.') + [''])[:2]
        int_part, frac_part = parts[0], parts[1]
        # sanitize integer part (allow leading + or -)
        if int_part.strip() == "":
            int_part = "0"
        int_part = int_part.lstrip('+')
        sign = ""
        if int_part.startswith('-'):
            sign = "MINUS "
            int_part = int_part[1:]
        # split into 3-digit groups from right
        groups = []
        s = int_part
        while s:
            groups.append(s[-3:])
            s = s[:-3]
        if not groups:
            groups = ["0"]
        words = []
        for idx, grp in enumerate(groups):
            grp = grp.zfill(3)
            gwords = self._three_to_words(grp)
            if gwords:
                scale = self.SCALES[idx] if idx < len(self.SCALES) else ""
                words.append((gwords + (" " + scale if scale else "")).strip())
        if not words:
            main = "ZERO"
        else:
            main = " ".join(reversed(words))
        frac_words = ""
        if frac_part:
            frac_words = "AND CENTS " + self._two_to_words(frac_part[:2]) + " "
        return f"{sign}{main} {frac_words}ONLY".strip()
    def _two_to_words(self, s):
        s = s.zfill(2)[:2]
        if s[0] == "0":
            return self.UNITS[int(s[1])]
        if s[0] == "1":
            return self.TEENS[int(s[1])]
        if s[1] == "0":
            return self.TENS[int(s[0])]
        return f"{self.TENS[int(s[0])]} {self.UNITS[int(s[1])]}"
    def _three_to_words(self, s):
        s = s.zfill(3)
        h, rest = int(s[0]), s[1:]
        parts = []
        if h > 0:
            parts.append(f"{self.UNITS[h]} HUNDRED")
            if rest != "00":
                parts.append("AND")
        if rest != "00":
            parts.append(self._two_to_words(rest))
        return " ".join(parts).strip()

