        self.NUMBER_TEEN = ["TEN", "ELEVEN", "TWELVE", "THIRTEEN", "FOURTEEN", "FIFTEEN", "SIXTEEN", "SEVENTEEN", "EIGHTEEN", "NINETEEN"]
        self.NUMBER_TEN = ["", "TEN", "TWENTY", "THIRTY", "FORTY", "FIFTY", "SIXTY", "SEVENTY", "EIGHTY", "NINETY"]
        self.SUFFIX = ["", "THOUSAND", "MILLION", "BILLION", "TRILLION"]
    def format(self, x):
        if x is None:
            return ""
        return self._format_str(str(x))
    def _format_str(self, s):
        left, right = (s.split('.') + [''])[:2]
        left = left.lstrip('+')
        sign = ""
        if left.startswith('-'):
            sign = "MINUS "
            left = left[1:]
        if left == "":
            left = "0"
        # break into chunks
        chunks = []
        while left:
            chunks.append(left[-3:].zfill(3))
            left = left[:-3]
        if not chunks:
            chunks = ["000"]
        parts = []
        for i, chunk in enumerate(chunks):
            word = self._chunk_to_words(chunk)
            if word:
                suffix = self.SUFFIX[i] if i < len(self.SUFFIX) else ""
                parts.append((word + (" " + suffix if suffix else "")).strip())
        if not parts:
            main = "ZERO"
        else:
            main = " ".join(reversed(parts))
        cents = ""
        if right:
            cents = "AND CENTS " + self._two(right[:2]) + " "
        return f"{sign}{main} {cents}ONLY".strip()
    def _two(self, s):
        s = s.zfill(2)[:2]
        if s[0] == '0':
            return self.NUMBER[int(s[1])]
        if s[0] == '1':
            return self.NUMBER_TEEN[int(s[1])]
        if s[1] == '0':
            return self.NUMBER_TEN[int(s[0])]
        return f"{self.NUMBER_TEN[int(s[0])]} {self.NUMBER[int(s[1])]}"
    def _chunk_to_words(self, chunk):
        if chunk == "000":
            return ""
        h = int(chunk[0])
        rest = chunk[1:]
        parts = []
        if h > 0:
            parts.append(f"{self.NUMBER[h]} HUNDRED")
            if rest != "00":
                parts.append("AND")
        if rest != "00":
            parts.append(self._two(rest))
        return " ".join(parts)

