        self.teens = ["TEN","ELEVEN","TWELVE","THIRTEEN","FOURTEEN","FIFTEEN","SIXTEEN","SEVENTEEN","EIGHTEEN","NINETEEN"]
        self.tens = ["", "", "TWENTY","THIRTY","FORTY","FIFTY","SIXTY","SEVENTY","EIGHTY","NINETY"]
        self.scales = ["", "THOUSAND", "MILLION", "BILLION", "TRILLION"]
    def format(self, x):
        if x is None:
            return ""
        return self._to_words(str(x))
    def _to_words(self, s):
        left,right = (s.split('.') + [''])[:2]
        left = left or "0"
        sign = ""
        if left.startswith('-'):
            sign = "MINUS "
            left = left[1:]
        n = int(left) if left.isdigit() else 0
        if n == 0:
            main = "ZERO"
        else:
            groups = []
            gi = 0
            while n > 0:
                rem = n % 1000
                if rem:
                    groups.append((self._under_thousand(rem) + ((" " + self.scales[gi]) if self.scales[gi] else "")).strip())
                n //= 1000
                gi += 1
            main = " ".join(reversed(groups))
        cents = ""
        if right:
            cents = "AND CENTS " + self._two_digits(right[:2]) + " "
        return f"{sign}{main} {cents}ONLY".strip()
    def _two_digits(self, s):
        s = s.zfill(2)[:2]
        a,b = int(s[0]), int(s[1])
        if a == 0:
            return self.ones[b] if b>0 else "ZERO"
        if a == 1:
            return self.teens[b]
        if b == 0:
            return self.tens[a]
        return f"{self.tens[a]} {self.ones[b]}"
    def _under_thousand(self, num):
        hundred = num // 100
        rem = num % 100
        parts = []
        if hundred:
            parts.append(f"{self.ones[hundred]} HUNDRED")
            if rem:
                parts.append("AND")
        if rem:
            parts.append(self._two_digits(str(rem)))
        return " ".join(parts)

