class NumberWordFormatter:
    def __init__(self):
        self.units = ["","ONE","TWO","THREE","FOUR","FIVE","SIX","SEVEN","EIGHT","NINE"]
        self.teens = ["TEN","ELEVEN","TWELVE","THIRTEEN","FOURTEEN","FIFTEEN","SIXTEEN","SEVENTEEN","EIGHTEEN","NINETEEN"]
        self.tens = ["","","TWENTY","THIRTY","FORTY","FIFTY","SIXTY","SEVENTY","EIGHTY","NINETY"]
        self.groups = ["","THOUSAND","MILLION","BILLION","TRILLION","QUADRILLION"]
    def format(self, x):
        if x is None:
            return ""
        return self.to_words(str(x))
    def to_words(self, s):
        left,right = (s.split('.') + [''])[:2]
        left = left or "0"
        sign = ""
        if left.startswith('-'):
            sign = "MINUS "
            left = left[1:]
        # convert integer part by numeric grouping
        try:
            n = int(left)
        except:
            n = 0
        if n == 0:
            main = "ZERO"
        else:
            parts = []
            gi = 0
            while n > 0:
                chunk = n % 1000
                if chunk:
                    part = self._chunk(chunk)
                    grpname = self.groups[gi] if gi < len(self.groups) else ""
                    parts.append((part + (" " + grpname if grpname else "")).strip())
                n //= 1000
                gi += 1
            main = " ".join(reversed(parts))
        cents = ""
        if right:
            cents = "AND CENTS " + self._two(right[:2]) + " "
        return f"{sign}{main} {cents}ONLY".strip()
    def _two(self, s):
        s = s.zfill(2)[:2]
        a,b = int(s[0]), int(s[1])
        if a == 0:
            return self.units[b] or "ZERO"
        if a == 1:
            return self.teens[b]
        if b == 0:
            return self.tens[a]
        return f"{self.tens[a]} {self.units[b]}"
    def _chunk(self, num):
        h = num // 100
        rem = num % 100
        pieces = []
        if h:
            pieces.append(f"{self.units[h]} HUNDRED")
            if rem:
                pieces.append("AND")
        if rem:
            if rem < 10:
                pieces.append(self.units[rem])
            elif rem < 20:
                pieces.append(self.teens[rem-10])
            else:
                pieces.append((self.tens[rem//10] + (" " + self.units[rem%10] if rem%10 else "")).strip())
        return " ".join(pieces)
